parameters.jsonBody:
={{
(() => {
  const plainText = $json.html
    .replace(/<h1>/g, "*")
    .replace(/<\/h1>/g, "*\n")
    .replace(/<h2>/g, "\n\n*")
    .replace(/<\/h2>/g, "*\n")
    .replace(/<[^>]+>/g, "")
    .trim();

  const chunkSize = 2800; // Safe margin under Slack limit
  const chunks = [];

  for (let i = 0; i < plainText.length; i += chunkSize) {
    chunks.push(plainText.substring(i, i + chunkSize));
  }

  const blocks = [
    {
      type: "section",
      text: {
        type: "mrkdwn",
        text: "*📰 Frontend Weekly Draft Generated*"
      }
    },
    {
      type: "section",
      text: {
        type: "mrkdwn",
        text: "🧠 Based on 8 latest articles\n📅 Generated at: " + new Date().toLocaleString()
      }
    },
    { type: "divider" }
  ];

  chunks.forEach(chunk => {
    blocks.push({
      type: "section",
      text: {
        type: "mrkdwn",
        text: chunk
      }
    });
  });

  return {
    text: "Frontend Weekly",
    blocks: blocks
  };
})()
}}
